  @action
  toggleIsLoading() {
    this.isLoading = !this.isLoading;

    clearTimeout(this.timer);
    // make it go back to the idle state
    this.timer = setTimeout(() =&gt; {
      this.isLoading = false;
    }, 4000);
  }

  @action
  cancelLoading() {
    this.isLoading = false;
  }
