#### Custom sort callback

To implement a custom sort callback on a column:

1. add a custom function as the value for `sortingFunction` in the column hash.
2. include a custom `onSort` action in your Table invocation to track the sorting order and use it in the custom sorting function.

This is useful for cases where the key might not be A-Z or 0-9 sortable by default, e.g., status, and you’re otherwise unable to influence the shape of the data in the model.

In this example, we are indicating that we want to sort on a status, which takes its order based on the position in the array:


<?php start="demo-block" classicComponentId="components/table/advanced-table/partials/code/code-snippets/advanced-table-custom-sort.classic" gtsComponentId="components/table/advanced-table/partials/code/code-snippets/advanced-table-custom-sort" hbs="&lt;Hds::AdvancedTable
  @model=&#123;&#123;this.myDemoData&#125;&#125;
  @columns=&#123;&#123;array
    (hash label=&quot;Peer name&quot; isSortable=true key=&quot;peer-name&quot;)
    (hash label=&quot;Status&quot; isSortable=true key=&quot;status&quot; sortingFunction=this.customSortingFunction)
    (hash label=&quot;Cluster partition&quot;)
  &#125;&#125;
  @sortBy=&quot;status&quot;
  @sortOrder=&quot;asc&quot;
  @onSort=&#123;&#123;this.customOnSort&#125;&#125;
&gt;
  &lt;:body as |B|&gt;
    &lt;B.Tr&gt;
      &lt;B.Td&gt;&#123;&#123;get B.data &quot;peer-name&quot;&#125;&#125;&lt;/B.Td&gt;
      &lt;B.Td&gt;&#123;&#123;get B.data &quot;status&quot;&#125;&#125;&lt;/B.Td&gt;
      &lt;B.Td&gt;&#123;&#123;get B.data &quot;cluster-partition&quot;&#125;&#125;&lt;/B.Td&gt;
    &lt;/B.Tr&gt;
  &lt;/:body&gt;
&lt;/Hds::AdvancedTable&gt;" js="import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

import CLUSTER_DATA from 'website/mocks/cluster-data';

// we use an array to declare the custom sorting order for the clusters' status
const customSortingCriteriaArray = [
  'failing',
  'active',
  'establishing',
  'pending',
];

export default class LocalComponent extends Component {
  // we track the sorting order, so it can be used in the custom sorting function
  @tracked customSortOrder = 'asc';

  get myDemoData() {
    return CLUSTER_DATA;
  }

  // we define a &quot;getter&quot; that returns a custom sorting function (&quot;s1&quot; and &quot;s2&quot; are data records)
  get customSortingFunction() {
    return (s1, s2) =&gt; {
      const index1 = customSortingCriteriaArray.indexOf(s1['status']);
      const index2 = customSortingCriteriaArray.indexOf(s2['status']);
      if (index1 &lt; index2) {
        return this.customSortOrder === 'asc' ? -1 : 1;
      } else if (index1 &gt; index2) {
        return this.customSortOrder === 'asc' ? 1 : -1;
      } else {
        return 0;
      }
    };
  }

  @action
  customOnSort(_sortBy, sortOrder) {
    this.customSortOrder = sortOrder;
  };
}" gts="import Component from '@glimmer/component';
