  &lt;Doc::Placeholder @height=&quot;40px&quot; @text=&quot;Item 4&quot; @background=&quot;#fff8d2&quot; /&gt;
&lt;/Hds::Layout::Grid&gt;" js="" gts="import type { TemplateOnlyComponent } from '@ember/component/template-only';

